/* ─── CURSOR ─── */
const dot=document.getElementById('cur-dot');
let mx=0,my=0,rafPending=false;
document.addEventListener('mousemove',e=>{
  mx=e.clientX;my=e.clientY;
  if(!rafPending){
    rafPending=true;
    requestAnimationFrame(()=>{
      dot.style.transform=`translate(${mx-4}px,${my-4}px)`;
      rafPending=false;
    });
  }
},{ passive:true });

/* ─── GLITCH periodic ─── */
const gt = document.getElementById('glitch-title');
setInterval(()=>{ gt.classList.add('glitch'); setTimeout(()=>gt.classList.remove('glitch'),250); }, 5000);

/* ─── PARTICLES ─── */
const canvas=document.getElementById('particles');
const ctx=canvas.getContext('2d');
let W,H;
function resize(){W=canvas.width=window.innerWidth;H=canvas.height=window.innerHeight;}
resize();window.addEventListener('resize',resize);
const cols=['#00d4ff','#b040ff','#ff3fa4','#00d4ff','#6eb8ff'];
const pts=Array.from({length:65},()=>({
  x:Math.random()*window.innerWidth,y:Math.random()*window.innerHeight,
  vx:(Math.random()-.5)*.3,vy:(Math.random()-.5)*.3,
  r:Math.random()*1.6+.3,
  color:cols[Math.floor(Math.random()*cols.length)],
  alpha:Math.random()*.5+.15
}));
function drawP(){
  ctx.clearRect(0,0,W,H);
  for(let i=0;i<pts.length;i++){
    for(let j=i+1;j<pts.length;j++){
      const dx=pts[i].x-pts[j].x,dy=pts[i].y-pts[j].y,d=Math.hypot(dx,dy);
      if(d<130){ctx.beginPath();ctx.moveTo(pts[i].x,pts[i].y);ctx.lineTo(pts[j].x,pts[j].y);ctx.strokeStyle=pts[i].color;ctx.globalAlpha=(1-d/130)*.1;ctx.lineWidth=.5;ctx.stroke();}
    }
  }
  pts.forEach(p=>{
    p.x+=p.vx;p.y+=p.vy;
    if(p.x<0)p.x=W;if(p.x>W)p.x=0;if(p.y<0)p.y=H;if(p.y>H)p.y=0;
    ctx.globalAlpha=p.alpha*.25;
    ctx.beginPath();ctx.arc(p.x,p.y,p.r*4,0,Math.PI*2);
    const g=ctx.createRadialGradient(p.x,p.y,0,p.x,p.y,p.r*4);
    g.addColorStop(0,p.color);g.addColorStop(1,'transparent');
    ctx.fillStyle=g;ctx.fill();
    ctx.globalAlpha=p.alpha;
    ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=p.color;ctx.fill();
  });
  ctx.globalAlpha=1;
  requestAnimationFrame(drawP);
}
drawP();

/* ─── SCROLL REVEAL ─── */
const reveals=document.querySelectorAll('.reveal');
const io=new IntersectionObserver(entries=>{
  entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('visible');io.unobserve(e.target);}});
},{threshold:.12});
reveals.forEach(r=>io.observe(r));

/* ─── 3D TILT ─── */
document.querySelectorAll('.servicio,.caso,.step').forEach(el=>{
  el.addEventListener('mousemove',e=>{
    const r=el.getBoundingClientRect();
    const x=(e.clientX-r.left)/r.width-.5;
    const y=(e.clientY-r.top)/r.height-.5;
    el.style.transform=`perspective(900px) rotateY(${x*10}deg) rotateX(${-y*10}deg) translateY(-5px)`;
  });
  el.addEventListener('mouseleave',()=>{el.style.transform='';});
});

/* ─── VIDEO DATA ─── */
const VID_SRC = "data:video/mp4;base64,";
document.getElementById('hero-vid-src').src = VID_SRC;
document.getElementById('hero-video').load();
document.getElementById('cta-vid-src').src = VID_SRC;
document.getElementById('cta-video').load();

// CTA video glitch periodic
const ctaGlitchEl = document.getElementById('cta-glitch');
setInterval(()=>{
  ctaGlitchEl.classList.add('active');
  setTimeout(()=>ctaGlitchEl.classList.remove('active'),150);
}, 3200);

/* ─── NAV ACTIVE ─── */
const sections=document.querySelectorAll('section[id]');
const navLinks=document.querySelectorAll('.nav-links a');
window.addEventListener('scroll',()=>{
  let current='';
  sections.forEach(s=>{if(window.scrollY>=s.offsetTop-100)current=s.id;});
  navLinks.forEach(a=>{
    if(a.id==='nav-manifiesto') return;
    a.style.color=a.getAttribute('href')==='#'+current?'var(--cyan)':'';
    a.style.textShadow=a.getAttribute('href')==='#'+current?'0 0 15px var(--cyan)':'';
  });
});

/* ─── MANIFIESTO MODAL ─── */
const mnfModal=document.getElementById('manifiesto-modal');
const mnfCloseBtn=document.getElementById('mnf-close-btn');
const navMnf=document.getElementById('nav-manifiesto');
let mnfRevealInit=false;

function openManifiesto(e){
  e.preventDefault();
  mnfModal.classList.add('mnf-open');
  mnfCloseBtn.classList.add('mnf-open');
  mnfModal.setAttribute('aria-hidden','false');
  mnfModal.scrollTop=0;
  document.body.style.overflow='hidden';
  initMnfReveal();
}
function closeManifiesto(){
  mnfModal.classList.remove('mnf-open');
  mnfCloseBtn.classList.remove('mnf-open');
  mnfModal.setAttribute('aria-hidden','true');
  document.body.style.overflow='';
}
function initMnfReveal(){
  if(mnfRevealInit)return;
  mnfRevealInit=true;
  const io=new IntersectionObserver(entries=>{
    entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target);}});
  },{threshold:.12,rootMargin:'0px 0px -40px 0px',root:mnfModal});
  mnfModal.querySelectorAll('.mnf-reveal').forEach(el=>io.observe(el));
}
navMnf.addEventListener('click',openManifiesto);
mnfCloseBtn.addEventListener('click',closeManifiesto);
document.addEventListener('keydown',e=>{if(e.key==='Escape'&&mnfModal.classList.contains('mnf-open'))closeManifiesto();});